GUIPayShopItem = class("GUIPayShopItem", IGUIWindow)

PayItemBuyStatus = {
    Buy = 1, --购买
    Used = 2, --已购买
    Using = 3, --使用中
}

function GUIPayShopItem:onLoad()
    self.kind = TabKind.NotKind
    self.itemId = 0
    self.selectMode = TabSelectStatus.NotSelect

    self.ivItemBg =  self:getChildWindow(0, GUIType.StaticImage)
    self.tvItemTitle = self:getChildWindow(0,GUIType.StaticText,self.ivItemBg)
    self.ivItemIcon = self:getChildWindow(1,GUIType.StaticImage,self.ivItemBg)

    self.btnItemButton = self:getChildWindow(1,GUIType.Button)
    self.ivItemMoneyIcon = self:getChildWindow(0,GUIType.StaticImage,self.btnItemButton)
    --shopItem.ivItemBg:registerEvent(GUIEvent.Click, function()

    self.ivItemBg:registerEvent(GUIEvent.Click,function()
        --print("+++++++++++++++")
        self:onClickItem()
    end)

    self.btnItemButton:registerEvent(GUIEvent.ButtonClick,function ()
        self:onClickButtonItem()
    end)

end

function GUIPayShopItem:getMoneyIconByMoneyType(Kind)

    local strMoneyIcon = ""
    if Kind == Define.MoneyType.SLGolds then
        --strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Golds)
        strMoneyIcon = "set:LiftingSimulatorShop1.json image:gold"
    end
    if Kind == Define.MoneyType.DiamondGolds2 then
        strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Diamonds)
        --strMoneyIcon = "set:LiftingSimulatorShop1.json image:DiamondBlues"
    end
    if Kind == Define.MoneyType.DiamondGolds1 then
        strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Diamonds)
        --strMoneyIcon = "set:LiftingSimulatorShop1.json image:DiamondGolds"
    end

    return strMoneyIcon

end


function GUIPayShopItem:initItem(Kind, Bg,Value)

    self.kind = Kind
    self.itemId = Value.Id

    self.ivItemBg:SetImage(Bg)
    self.tvItemTitle:SetText(Lang:getString(Value.Name))
    self.ivItemIcon:SetImage(Value.Icon)

    --local MoneyIcon = self:getMoneyIconByMoneyType(Value.MoneyType)
    --self.ivItemMoneyIcon:SetImage(MoneyIcon)
    --self.btnItemButton:SetText(Utility.toKMBString(tostring(Value.Price),2))

    self.btnItemButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button")
    self.btnItemButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button")

    if self.kind == PayTabKind.Privilege then
            self:initPrivilegeItem(Value)
    end
    if self.kind == PayTabKind.Skin then
            self:initSkinItem(Value)
    end
end

function GUIPayShopItem:initPrivilegeItem(Value)

    if Value.Status == PayItemBuyStatus.Buy then

        local MoneyIcon = self:getMoneyIconByMoneyType(Value.MoneyType)
        self.ivItemMoneyIcon:SetImage(MoneyIcon)
        self.ivItemMoneyIcon:SetVisible(true)
        self.btnItemButton:SetText(tostring(Value.Price))
        self.btnItemButton:SetRenderOffset({ x = 20, y = 0 })
        self.btnItemButton:SetEnabled(true)

    elseif Value.Status == PayItemBuyStatus.Used then

        local strButtonTitle = "GUIPayShop_Have"
        self.ivItemMoneyIcon:SetVisible(false)
        self.btnItemButton:SetText(Lang:getString(strButtonTitle))
        self.btnItemButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnItemButton:SetEnabled(false)

    elseif Value.Status == PayItemBuyStatus.Using then

    end
end

function GUIPayShopItem:initSkinItem(Value)

    if Value.Status == PayItemBuyStatus.Buy then
        local MoneyIcon = self:getMoneyIconByMoneyType(Value.MoneyType)
        self.ivItemMoneyIcon:SetImage(MoneyIcon)
        self.ivItemMoneyIcon:SetVisible(true)
        self.btnItemButton:SetText(tostring(Value.Price))
        self.btnItemButton:SetRenderOffset({ x = 20, y = 0 })

    elseif Value.Status == PayItemBuyStatus.Used then

        local strButtonTitle = "GUIPayShop_Used" --使用
        self.ivItemMoneyIcon:SetVisible(false)
        self.btnItemButton:SetText(Lang:getString(strButtonTitle))
        self.btnItemButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnItemButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button3")
        self.btnItemButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button3")

    elseif Value.Status == PayItemBuyStatus.Using then

        local strButtonTitle = "GUIPayShop_Unload" --卸下
        self.ivItemMoneyIcon:SetVisible(false)
        self.btnItemButton:SetText(Lang:getString(strButtonTitle))
        self.btnItemButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnItemButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button2")
        self.btnItemButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button2")
    end

end

function GUIPayShopItem:onClickItem()

    --print("IIIIIIIIIIIIIIIIIIIIIIII")
    --ShopItemClickEvent:invoke(self.itemId)
    PayShopItemClickEvent:invoke(self.itemId)

end

function GUIPayShopItem:onClickButtonItem()

    PayShopItemClickButtonEvent:invoke(self.itemId)

end

function GUIPayShopItem:changeSelectStatus(Bg, SelectMode)

    self.ivItemBg:SetImage(Bg)
    self.selectMode = SelectMode

end

return GUIPayShopItem



